        return new Source("{% extends 'base.html.twig' %}

{% block title %}Modifier mon profil - BioSync{% endblock %}

{% block body %}
<div class=\"app-layout\">
    {% include 'partials/_sidebar.html.twig' with {'active': 'profile'} %}

    <main class=\"main-content\">
        <div class=\"page-header\">
            <h1 class=\"page-title\">Modifier mon profil</h1>
            <p class=\"page-subtitle\">Mettez a jour vos informations personnelles.</p>
        </div>

        <div class=\"card\" style=\"max-width: 600px;\">
            {{ form_start(form) }}
                <div class=\"form-group\">
                    {{ form_label(form.nomComplet) }}
                    {{ form_widget(form.nomComplet) }}
                    {{ form_errors(form.nomComplet) }}
                </div>

                <div class=\"form-group\">
                    {{ form_label(form.email) }}
                    {{ form_widget(form.email) }}
                    {{ form_errors(form.email) }}
                </div>

                <div class=\"modal-footer\" style=\"margin-top: 2rem; padding-top: 1rem; border-top: 1px solid var(--gray-200);\">
                    <a href=\"{{ path('app_profile') }}\" class=\"btn btn-ghost\">Annuler</a>
                    <button type=\"submit\" class=\"btn btn-primary\">Enregistrer</button>
                </div>
            {{ form_end(form) }}
        </div>
    </main>
</div>
{% endblock %}
", "profile/edit.html.twig", "C:\\biosync_new\\templates\\profile\\edit.html.twig");
